def index(self, key):
    """
    以整数形式返回键。
    返回给定项的索引。

    :param key: 一个键
    :return: 索引
    :rtype: int
    """
    try:
        return self.keys().index(key)
    except ValueError:
        raise KeyError(f"Key {key} not found")

def values(self, *keys):
    """
    以列表的形式返回通过 `self.index` 过滤的键。
    返回记录的值，可以选择性地通过索引或键进行过滤，仅包含特定的值。

    :param keys: 要包含的项目的索引或键；如果未提供任何参数，则包含所有值
    :return: 值的列表
    :rtype: list
    """
    if not keys:
        # 如果没有提供键，返回所有值
        return list(self.index.values())

    result = []
    for key in keys:
        # 如果key是整数，按索引获取值
        if isinstance(key, int):
            try:
                result.append(list(self.index.values())[key])
            except IndexError:
                continue
        # 否则按键获取值
        else:
            if key in self.index:
                result.append(self.index[key])

    return result

def begin(self, mode=None, bookmarks=None, metadata=None, timeout=None, db=None, imp_user=None, dehydration_hooks=None, hydration_hooks=None, **handlers):
    # Set default mode to WRITE if not specified
    if mode is None:
        mode = "WRITE"
    elif mode not in ("READ", "WRITE"):
        raise ValueError("Mode must be either 'READ' or 'WRITE'")

    # Initialize parameters dictionary
    parameters = {}

    # Add bookmarks if provided
    if bookmarks:
        parameters["bookmarks"] = list(bookmarks)

    # Add metadata if provided
    if metadata:
        parameters["metadata"] = metadata

    # Add timeout if provided
    if timeout is not None:
        parameters["timeout"] = timeout

    # Add database name if provided (Bolt 4.0+)
    if db is not None:
        parameters["db"] = db

    # Add impersonated user if provided (Bolt 4.4+)
    if imp_user is not None:
        parameters["imp_user"] = imp_user

    # Create transaction context with hooks
    tx_context = {
        "mode": mode,
        "parameters": parameters
    }

    if dehydration_hooks:
        tx_context["dehydration_hooks"] = dehydration_hooks
    if hydration_hooks:
        tx_context["hydration_hooks"] = hydration_hooks

    # Create and return Response object with handlers
    response = Response(tx_context)
    for key, handler in handlers.items():
        response.add_handler(key, handler)

    return response

def point_type(name, fields, srid_map):
    """
    动态创建一个 Point 子类。
    """
    class_attrs = {
        '__slots__': tuple(fields) + ('srid',),
        '_srid_map': srid_map
    }

    def __init__(self, *args, **kwargs):
        if len(args) > len(fields):
            raise TypeError(f"Expected {len(fields)} arguments, got {len(args)}")

        # Set values from positional args
        for field, value in zip(fields, args):
            setattr(self, field, value)

        # Set remaining fields from kwargs
        for field in fields[len(args):]:
            if field in kwargs:
                setattr(self, field, kwargs[field])
            else:
                setattr(self, field, None)

        # Set SRID
        self.srid = kwargs.get('srid', None)

    def __repr__(self):
        values = [getattr(self, field) for field in fields]
        fields_str = ', '.join(f'{f}={v!r}' for f, v in zip(fields, values))
        if self.srid is not None:
            fields_str += f', srid={self.srid!r}'
        return f'{name}({fields_str})'

    class_attrs['__init__'] = __init__
    class_attrs['__repr__'] = __repr__

    return type(name, (), class_attrs)

def deprecated(message):
    """
    返回一个用于标记函数和方法为已弃用的装饰器函数。
    用于标记函数和方法为已弃用的装饰器。
    @deprecated("'foo' has been deprecated in favour of 'bar'")
        def foo(x):
            pass
    """
    import warnings
    import functools

    def deprecated_decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            warnings.warn(
                f"{func.__name__} is deprecated: {message}",
                category=DeprecationWarning,
                stacklevel=2
            )
            return func(*args, **kwargs)
        return wrapper
    return deprecated_decorator

def parse_version(s: str) -> tuple[int, ...]:
    """
