    如果类中存在指定的键（key），则返回与该键对应的值；否则，返回默认值
    如果键 `k` 存在于字典 `D` 中,则`D.get(k[, d]) -> D[k]`；否则返回默认值 `None`。
    """
    try:
        return self[key]
    except KeyError:
        return default

def _getTargetClass(self):
    """
    定义此方法以返回当前使用的实现类，并去掉 'Py' 或 'Fallback' 后缀。
    """
    class_name = self.__class__.__name__
    if class_name.endswith('Py'):
        return class_name[:-2]
    elif class_name.endswith('Fallback'):
        return class_name[:-8]
