def to_csv(self, separator=", ", header=None):
    # Start with header if provided
    result = []
    if header is not None:
        result.append(header + "\n")

    # Process each point in the graph
    for point in self.points:
        # Convert coordinates to strings and join with separator
        coords = separator.join(str(x) for x in point.coordinates)

        # Convert values to strings and join with separator
        if hasattr(point, 'values'):
            values = separator.join(str(v) for v in point.values)
            # Combine coordinates and values
            line = coords + separator + values
        else:
            line = coords

        # Add newline and append to result
        result.append(line + "\n")

    # Join all lines and return
    return "".join(result)

def _get_err_indices(self, coord_name):
    """
    查找与 `coord_name` 对应的所有错误索引。
    获取与某个坐标对应的错误索引。
    """
    err_indices = []
    for i, coord in enumerate(self.coords):
        if coord == coord_name and self.errors[i]:
            err_indices.append(i)
    return err_indices

def _update_context(self, context):
    # Get field names from the graph
    fields = self.fields()

    # Initialize error dict if not exists
    if not hasattr(context, 'error'):
        context.error = {}

    # Map coordinate names to x,y,z
    coord_map = {0: 'x', 1: 'y', 2: 'z'}

    # Look for error fields
    for field in fields:
        if 'error' in field.lower():
            # Extract base field name and error type
            parts = field.split('_')
            if len(parts) >= 3 and parts[-2] == 'error':
                base_field = parts[0]
                error_type = parts[-1]  # low/high

                # Find index of base field
                try:
                    base_idx = fields.index(base_field)
                    coord_name = coord_map.get(base_idx)

                    if coord_name:
                        # Create error entry if not exists
                        if coord_name not in context.error:
                            context.error[coord_name] = {}

                        # Add error field index
                        error_key = f"{coord_name}_{error_type}"
                        field_idx = fields.index(field)
                        context.error[coord_name][error_type] = {"index": field_idx}

                except ValueError:
                    # Base field not found, skip
                    continue

    return context

def is_fill_request_seq(seq):
    from collections.abc import Sequence
    from typing import Union

    # Helper function to check if an item is a FillRequest
    def is_fill_request(item):
        # Assuming FillRequest is a class/type that exists in the codebase
        try:
            return isinstance(item, FillRequest)
        except NameError:
            return False

    # Check if seq is a Source sequence
    try:
        if isinstance(seq, Source):
            return False
    except NameError:
        pass

    # Handle single item case
    if not isinstance(seq, Sequence):
        return is_fill_request(seq)

    # Handle sequence case
    has_fill_request = False
    for item in seq:
        if is_fill_request(item):
            has_fill_request = True
            break

    return has_fill_request

def is_run_el(obj):
    """
    检查 obj 类是否具有 run 方法。
    对象包含可执行的方法 'run'。
    """
    return hasattr(obj, 'run') and callable(getattr(obj, 'run'))

def difference(d1, d2, level=-1):
    """
    返回一个字典，其中包含 *d1* 中不在 *d2* 中的项。

    参数 *level* 用于设置递归的最大深度。对于无限递归，则将其设置为-1。如果设置为 1，当某个键同时存在于 *d1* 和 *d2* 中但其值不同，则该键值对会包含在差异结果中。
    有关更多详细信息，请参阅 :func:`intersection`。

    *d1* 和 *d2* 本身不会被修改。然而，*d1* 或其某些子字典可能会直接作为返回值。如果需要，请对结果进行深拷贝。
    """
    result = {}

    # 遍历d1中的所有键值对
    for key, value in d1.items():
        # 如果键不在d2中，直接添加到结果中
        if key not in d2:
            result[key] = value
        # 如果键在d2中且level不为0
        elif level != 0:
            # 如果两个值都是字典，则递归比较
            if isinstance(value, dict) and isinstance(d2[key], dict):
                # 递归调用，level减1
                nested_diff = difference(value, d2[key], level - 1 if level > 0 else -1)
                if nested_diff:
                    result[key] = nested_diff
            # 如果值不相等，且level为1或-1，则添加到结果中
            elif value != d2[key]:
                result[key] = value

    return result

def _validate_labels(labels):
    """
    检查给定标签中的键和值是否通过 `validate_key()` 和 `validate_value()` 验证。
    检查给定标签中的键和值是否符合其对应的正则表达式。

    参数:
        labels (dict): 需要验证的不同标签。

    异常:
        ValidationError: 如果任何键或值不符合其对应的正则表达式，将抛出此异常。
    """
    errors = []

    if not isinstance(labels, dict):
        raise ValidationError("Labels must be a dictionary")

    for key, value in labels.items():
        # Validate key
        try:
            if not isinstance(key, (str, bytes)):
                errors.append({str(key): 'expected string or bytes-like object'})
                continue

            if not validate_key(key):
                errors.append({key: f"Label key '{key}' does not match the regex [...]"})
        except Exception as e:
            errors.append({str(key): str(e)})

        # Validate value  
        try:
            if not isinstance(value, (str, bytes)):
                errors.append({str(value): 'expected string or bytes-like object'})
                continue

            if not validate_value(value):
                errors.append({value: f"Label value '{value}' does not match the regex [...]"})
        except Exception as e:
            errors.append({str(value): str(e)})

    if errors:
        raise ValidationError(messages=errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    result = {}

    # Handle first level special fields
    if first_level:
        # Copy identifier fields from manifest
        identifier_fields = ['apiVersion', 'kind', 'metadata']
        for field in identifier_fields:
            if field in manifest_dict:
                result[field] = manifest_dict[field]

    # Process all fields in manifest_dict
    for key, value in manifest_dict.items():
        # Skip if key already processed for first level
        if first_level and key in result:
            continue

        if isinstance(value, dict):
            # Recursively process nested dictionaries
            result[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            # Process lists using a helper function
            result[key] = generate_default_observer_schema_list(value)
        else:
            # Set non-dict and non-list values to None
            result[key] = None

    return result

def generate_default_observer_schema_list(manifest_list):
    """Helper function to process lists in the manifest"""
    if not manifest_list:
        return []

    # Take first item as sample
    sample = manifest_list[0]

    if isinstance(sample, dict):
        return [generate_default_observer_schema_dict(sample)]
    elif isinstance(sample, list):
        return [generate_default_observer_schema_list(sample)]
    else:
        return [None]

def update_last_applied_manifest_list_from_resp(last_applied_manifest, observer_schema, response):
    # Handle empty cases
    if not observer_schema or not response:
        return

    # Ensure last_applied_manifest has enough elements
    while len(last_applied_manifest) < len(response):
        last_applied_manifest.append({})

    # Process each element in the response list
    for i, resp_item in enumerate(response):
        if i >= len(observer_schema):
            break

        schema_item = observer_schema[i]

        # Skip if schema item is not a dict
        if not isinstance(schema_item, dict):
            continue

        # Initialize empty dict if needed
        if not isinstance(last_applied_manifest[i], dict):
            last_applied_manifest[i] = {}

        # Update fields based on schema
        for field, value in resp_item.items():
            if field in schema_item:
                if isinstance(value, dict) and isinstance(schema_item[field], dict):
                    # Recursively handle nested dicts
                    if field not in last_applied_manifest[i]:
                        last_applied_manifest[i][field] = {}
                    update_last_applied_manifest_dict_from_resp(
                        last_applied_manifest[i][field],
                        schema_item[field],
                        value
                    )
                elif isinstance(value, list) and isinstance(schema_item[field], list):
                    # Recursively handle nested lists
                    if field not in last_applied_manifest[i]:
                        last_applied_manifest[i][field] = []
                    update_last_applied_manifest_list_from_resp(
                        last_applied_manifest[i][field],
                        schema_item[field],
                        value
                    )
                else:
                    # Direct value assignment
                    last_applied_manifest[i][field] = value

def update_last_applied_manifest_dict_from_resp(last_applied_manifest, observer_schema, response):
    # Iterate through all fields in observer schema
    for field_name, field_schema in observer_schema.items():
        # If field not initialized in last_applied_manifest, initialize it
        if field_name not in last_applied_manifest:
            last_applied_manifest[field_name] = {}

        # If field not in response, raise KeyError
        if field_name not in response:
            raise KeyError(f"Field {field_name} not found in Kubernetes response")

        # If field schema is a dict, recursively update nested fields
        if isinstance(field_schema, dict):
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[field_name],
                field_schema,
                response[field_name]
            )
        # Otherwise copy value directly from response
        else:
            last_applied_manifest[field_name] = response[field_name]

    return last_applied_manifest

def generate_default_observer_schema(app):
    """
    为 ``spec.manifest`` 中的每个 Kubernetes 资源生成默认的观察者模式（observer schema），前提是尚未为其指定自定义的观察者模式。

    参数：
        app (krake.data.kubernetes.Application): 需要为其生成默认观察者模式的应用程序。
    """
    if not app.spec.observer:
        app.spec.observer = {}

    for resource in app.spec.manifest:
        # 获取资源的 kind 和 apiVersion
        kind = resource.get('kind')
        api_version = resource.get('apiVersion')

        # 如果资源没有 kind 或 apiVersion,跳过
        if not kind or not api_version:
            continue

        # 生成资源的唯一标识符
        resource_id = f"{api_version}/{kind}"

        # 如果该资源还没有观察者模式,则生成默认的
        if resource_id not in app.spec.observer:
            app.spec.observer[resource_id] = {
                "conditions": [
                    {
                        "type": "Available",
                        "status": "True"
                    }
                ]
            }

            # 为某些特定资源类型添加额外的默认观察条件
            if kind.lower() in ['deployment', 'statefulset', 'daemonset']:
                app.spec.observer[resource_id]["conditions"].append({
                    "type": "Progressing",
                    "status": "True"
                })

            # 为Job类型添加特定的完成条件
            if kind.lower() == 'job':
                app.spec.observer[resource_id]["conditions"] = [{
                    "type": "Complete",
                    "status": "True"
                }]

    return app

def format(
    self,
    sql: AnyStr,
    params: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    """
    将 SQL 使用 `self._converter.convert` 方法进行转换

    将 SQL 查询从 in-style 参数转换为 out-style 参数。

    *sql*（类型：`str` 或 `bytes`）是 SQL 查询语句。

    *params*（类型：`~collections.abc.Mapping` 或 `~collections.abc.Sequence`）包含一组 in-style 参数。它将每个参数（类型：`str` 或 `int`）映射到对应的值。如果 `SQLParams.in_style` 是命名参数样式，那么 *params* 必须是一个 `~collections.abc.Mapping` 类型。如果 `SQLParams.in_style` 是序号参数样式，那么 **params** 必须是一个 `~collections.abc.Sequence` 类型。

    返回一个包含以下内容的元组（`tuple`）：

      - 格式化后的 SQL 查询（类型：`str` 或 `bytes`）。

      - 转换后的 out-style 参数集合（类型：`dict` 或 `list`）。
    """
    # 检查参数类型是否匹配样式
    if self.in_style.is_named():
        if not isinstance(params, Mapping):
            raise TypeError("Named parameter style requires a mapping for params")
    else:
        if not isinstance(params, Sequence) or isinstance(params, (str, bytes)):
            raise TypeError("Positional parameter style requires a sequence for params")

    # 初始化输出参数集合
    out_params: Union[Dict[Union[str, int], Any], List[Any]]
    out_params = {} if self.out_style.is_named() else []

    # 初始化参数计数器和SQL构建器
    param_count = 0
    formatted_sql = sql

    if isinstance(sql, str):
        # 处理字符串类型的SQL
        if self.in_style.is_named():
            # 处理命名参数
            for param_name in params:
                param_value = params[param_name]
                converted_value = self._converter.convert(param_value)

                if self.out_style.is_named():
                    out_param_name = f"p{param_count}"
                    out_params[out_param_name] = converted_value
                    formatted_sql = formatted_sql.replace(
                        f"{self.in_style.prefix}{param_name}{self.in_style.suffix}",
                        f"{self.out_style.prefix}{out_param_name}{self.out_style.suffix}"
                    )
                else:
                    out_params.append(converted_value)
                    formatted_sql = formatted_sql.replace(
                        f"{self.in_style.prefix}{param_name}{self.in_style.suffix}",
                        self.out_style.placeholder
                    )
                param_count += 1
        else:
            # 处理序号参数
            for param_value in params:
                converted_value = self._converter.convert(param_value)

                if self.out_style.is_named():
                    out_param_name = f"p{param_count}"
                    out_params[out_param_name] = converted_value
                    formatted_sql = formatted_sql.replace(
                        self.in_style.placeholder,
                        f"{self.out_style.prefix}{out_param_name}{self.out_style.suffix}",
                        1
                    )
                else:
                    out_params.append(converted_value)
                    formatted_sql = formatted_sql.replace(
                        self.in_style.placeholder,
                        self.out_style.placeholder,
                        1
                    )
                param_count += 1
    else:
        # 处理bytes类型的SQL
        formatted_sql = sql
        if isinstance(params, Mapping):
            out_params = {k: self._converter.convert(v) for k, v in params.items()}
        else:
            out_params = [self._converter.convert(v) for v in params]

    return formatted_sql, out_params

def status_str(self, prefix=''):
    """
    通过访问排序后的 `self.messages` 列表，返回一个字符串。每次访问时，将前缀（prefix）和排序后的 `self.messages` 列表中的元素添加到结果中。
    返回验证器状态的字符串，并可选择性地添加前缀。
    """
    result = []
    for message in sorted(self.messages):
        result.append(prefix + message)
    return '\n'.join(result)

def status_str(self, prefix=''):
    """
    返回带有 self.log.status_str 的字符串表示形式，可选添加前缀。
    返回验证日志的字符串表示形式，可选添加前缀。
    """
    if hasattr(self, 'log') and hasattr(self.log, 'status_str'):
        status = self.log.status_str
    else:
        status = ''

    if prefix:
        return f"{prefix}{status}"
    return status

def validate(self, inventory, extract_spec_version=False):
    """
    验证给定的库存（inventory）。如果 `extract_spec_version` 为 True，则会根据 `type` 值来确定规范版本。如果没有 `type` 值或其无效，则其他测试将基于 `self.spec_version` 中给定的版本。
    验证给定的库存。

    如果 `extract_spec_version` 为真，则会根据 `type` 值来确定规范版本。
    如果没有 `type` 值或其无效，则其他测试将基于 `self.spec_version` 中给定的版本。
    """
    if not isinstance(inventory, dict):
        raise ValueError("Inventory must be a dictionary")

    # Extract spec version from type if requested
    if extract_spec_version:
        try:
            type_str = inventory.get('type', '')
            if type_str.startswith('inventory:'):
                version = type_str.split(':')[1]
                self.spec_version = version
        except (AttributeError, IndexError):
            pass # Fall back to self.spec_version

    # Validate required fields
    required_fields = ['type', 'items']
    for field in required_fields:
        if field not in inventory:
            raise ValueError(f"Missing required field: {field}")

    # Validate type format
    type_str = inventory['type']
    if not isinstance(type_str, str) or not type_str.startswith('inventory:'):
        raise ValueError("Invalid type format. Must start with 'inventory:'")

    # Validate items
    items = inventory['items']
    if not isinstance(items, list):
        raise ValueError("Items must be a list")

    # Validate each item
    for item in items:
        if not isinstance(item, dict):
            raise ValueError("Each item must be a dictionary")

        # Validate required item fields based on spec version
        item_required_fields = ['id', 'name']
        if self.spec_version >= '2.0':
            item_required_fields.extend(['quantity', 'unit'])

        for field in item_required_fields:
            if field not in item:
                raise ValueError(f"Missing required field in item: {field}")

    return True

def check_digests_present_and_used(self, manifest_files, digests_used):
    """
    检查清单（manifest）中所有需要的摘要（digest）是否存在并被使用。在类中返回 `error()`。
    """
    # 遍历所有清单文件
    for manifest in manifest_files:
        # 获取清单中的摘要列表
        manifest_digests = set()
        try:
            for layer in manifest.get('layers', []):
                if 'digest' in layer:
                    manifest_digests.add(layer['digest'])
            if 'config' in manifest and 'digest' in manifest['config']:
                manifest_digests.add(manifest['config']['digest'])
        except (KeyError, TypeError):
            return self.error(f"Invalid manifest format in {manifest}")

        # 检查所有摘要是否都被使用
        unused_digests = manifest_digests - set(digests_used)
        if unused_digests:
            return self.error(f"Found unused digests in manifest: {unused_digests}")

        # 检查是否所有使用的摘要都在清单中
        missing_digests = set(digests_used) - manifest_digests
        if missing_digests:
            return self.error(f"Missing digests in manifest: {missing_digests}")

    return None

def validate_as_prior_version(self, prior):
    """
    检查 `prior` 是否是当前库存（inventory）对象的有效先前版本。

    输入变量 `prior` 也应是一个 `InventoryValidator` 对象，并且假定 `self` 和 `prior` 的库存对象都已经过内部一致性检查。在类中返回 `error()`。
    """
    # 检查prior是否为InventoryValidator对象
    if not isinstance(prior, type(self)):
        return self.error("Prior version must be an InventoryValidator object")

    # 检查时间戳,确保prior是较早的版本
    if prior.timestamp >= self.timestamp:
        return self.error("Prior version must have earlier timestamp")

    # 检查库存变化的合理性
    for item_id in set(self.inventory.keys()) | set(prior.inventory.keys()):
        prior_qty = prior.inventory.get(item_id, 0)
        current_qty = self.inventory.get(item_id, 0)

        # 检查数量变化是否合理
        if current_qty < 0:
            return self.error(f"Invalid negative quantity for item {item_id}")

        # 检查数量变化是否过大
        if abs(current_qty - prior_qty) > self.max_change_threshold:
            return self.error(f"Unreasonable quantity change for item {item_id}")

    # 所有检查都通过
    return None

def get_logical_path_map(inventory, version):
    """
    返回库存（inventory）中各状态的文件路径，并以字典类型表示。
    获取库存中某个版本的状态逻辑路径到磁盘文件的映射。

    返回一个字典：`logical_path_in_state -> set(content_files)`

    集合`content_files`可能包含对比所描述版本更高版本中重复文件的引用。
    """
    logical_path_map = {}

    # 遍历库存中的所有版本
    for ver in inventory.versions:
        # 只处理指定版本及更高版本
        if ver >= version:
            # 遍历该版本中的所有文件
            for file_path, content_file in ver.files.items():
                # 如果逻辑路径不在映射中，创建新集合
                if file_path not in logical_path_map:
                    logical_path_map[file_path] = set()

                # 将内容文件添加到对应逻辑路径的集合中
                logical_path_map[file_path].add(content_file)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    验证库存（inventory）中的校验（fixity）块。检查校验块的结构，并保证仅引用了清单中列出的文件。在类中返回`error()`。
    """
    if not isinstance(fixity, dict):
        return self.error("Fixity block must be a dictionary")

    # Check required fields
    required_fields = ["message-digest-algorithm", "message-digest"]
    for field in required_fields:
        if field not in fixity:
            return self.error(f"Missing required field '{field}' in fixity block")

    # Validate algorithm field
    if not isinstance(fixity["message-digest-algorithm"], str):
        return self.error("message-digest-algorithm must be a string")

    # Validate digest field
    digests = fixity["message-digest"]
    if not isinstance(digests, list):
        return self.error("message-digest must be a list")

    # Check each digest entry
    for digest in digests:
        if not isinstance(digest, dict):
            return self.error("Each message-digest entry must be a dictionary")

        if "file" not in digest or "hash" not in digest:
            return self.error("Each message-digest entry must have 'file' and 'hash' fields")

        if not isinstance(digest["file"], str) or not isinstance(digest["hash"], str):
            return self.error("Digest file and hash values must be strings")

        # Verify file exists in manifest
        if digest["file"] not in manifest_files:
            return self.error(f"Digest references non-existent file: {digest['file']}")

    return None

def add_rendition(self, lang, file_path):
    """
    将类中由 `filepath()` 调用的文件路径分配给类中 `_renditions` 的 "lang"。

    {
        "original": "artigo02.pdf",
        "en": "artigo02-en.pdf",
    }
