def tzname_in_python2(namefunc):
    """
    在 Python 2 中将 Unicode 输出转换为字节字符串

    在 Python 3 中，tzname() API 发生了变化。它曾经返回字节字符串，但在 Python 3 中被更改为返回 Unicode 字符串。
    """
    def convert_to_string(name):
        # 如果是None直接返回
        if name is None:
            return None

        # 如果是bytes类型直接返回
        if isinstance(name, bytes):
            return name

        # 如果是unicode类型,转换为bytes
        if isinstance(name, str):
            return name.encode('ascii')

        # 其他类型抛出异常
        raise TypeError('tzname must return None or a string')

    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)

        # 如果返回的是元组(处理多个时区名称的情况)
        if isinstance(result, tuple):
            return tuple(convert_to_string(n) for n in result)

        return convert_to_string(result)

    return wrapper

def get_versions():
    """
    获取版本信息。如果无法获取版本信息，则返回默认值。
    获取版本信息或在无法获取时返回默认值
    """
    try:
        # 尝试获取版本信息
        import pkg_resources
        versions = {}

        # 获取已安装包的版本信息
        installed_packages = pkg_resources.working_set
        for package in installed_packages:
            versions[package.key] = package.version

        return versions

    except Exception:
        # 如果获取失败,返回默认值
        return {
            'python': '3.x',
            'pip': 'unknown',
            'setuptools': 'unknown'
        }

def render(pieces, style):
    """
    将输入的组件和样式渲染为对应的样式。
    将给定的组件渲染为要求的样式。
    """
    rendered = []

    # 遍历所有组件
    for piece in pieces:
        # 根据样式类型进行渲染
        if style == "bold":
            rendered.append(f"**{piece}**")
        elif style == "italic":
            rendered.append(f"*{piece}*")
        elif style == "underline":
            rendered.append(f"_{piece}_")
        else:
            # 默认不添加样式
            rendered.append(piece)

    # 将渲染后的组件连接起来
    return "".join(rendered)

def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    验证存储根层次结构。

    返回:
        num_objects (int): 检查的对象数量。
        good_objects (int): 检查后被认为有效的对象数量。
    """
    num_objects = 0
    good_objects = 0

    # 遍历所有存储对象
    for obj in self.get_all_objects():
        num_objects += 1

        try:
            # 验证对象完整性
            if validate_objects:
                obj.validate()

            # 检查摘要值
            if check_digests:
                stored_digest = obj.get_digest()
                calculated_digest = obj.calculate_digest()
                if stored_digest != calculated_digest:
                    if show_warnings:
                        print(f"Warning: Digest mismatch for object {obj.id}")
                    continue

            good_objects += 1

        except Exception as e:
            if show_warnings:
                print(f"Warning: Failed to validate object {obj.id}: {str(e)}")
            continue

    return num_objects, good_objects

def validate_version_inventories(self, version_dirs):
    """
    每个版本**应当**包含截至该版本的完整清单。  

    同时，记录所有与根清单不同的内容摘要，以便在验证内容时能够检查这些差异。  

    `version_dirs` 是一个包含版本目录名称的数组，并假定按照版本顺序排列（1, 2, 3...）。
    """
    # 存储每个版本的清单差异
    version_diffs = {}

    # 获取根目录清单
    root_inventory = self.get_root_inventory()

    # 遍历每个版本目录
    for version in version_dirs:
        version_inventory = self.get_version_inventory(version)

        # 检查是否包含完整清单
        if not version_inventory:
            raise ValueError(f"Version {version} missing complete inventory")

        # 与根清单比较,记录差异
        diffs = {}
        for file_path, checksum in version_inventory.items():
            if file_path not in root_inventory:
                diffs[file_path] = {'status': 'added', 'checksum': checksum}
            elif root_inventory[file_path] != checksum:
                diffs[file_path] = {
                    'status': 'modified',
                    'old_checksum': root_inventory[file_path],
                    'new_checksum': checksum
                }

        for file_path in root_inventory:
            if file_path not in version_inventory:
                diffs[file_path] = {
                    'status': 'deleted',
                    'old_checksum': root_inventory[file_path]
                }

        # 存储该版本的差异
        if diffs:
            version_diffs[version] = diffs

    return version_diffs

def amend_bzparams(self, params, bug_ids):
    """
    修改 Bugzilla 参数
    """
    if not params or not bug_ids:
        return params

    # Convert single bug_id to list
    if isinstance(bug_ids, (int, str)):
        bug_ids = [str(bug_ids)]
    else:
        bug_ids = [str(bug_id) for bug_id in bug_ids]

    # Add bug_ids to params
    if len(bug_ids) == 1:
        params['id'] = bug_ids[0]
    else:
        params['ids'] = bug_ids

    return params

def parser_flags(parser):
    flags = []
    for action in parser._actions:
        # Skip help action
        if action.dest == 'help':
            continue
        # Get all option strings (flags) for this action
        flags.extend(action.option_strings)
    # Sort flags and join with spaces
    return ' '.join(sorted(flags))

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    给定一个参数序列和一个从子解析器名称到 argparse.ArgumentParser 实例的字典，让每个请求的操作的子解析器尝试解析所有参数。这允许共享常见参数（例如 --repository）给多个子解析器。

    将结果作为一个元组返回，其中包含一个将子解析器名称映射到其解析后的 argparse.Namespace 实例的字典和一个包含未被任何子解析器认领的剩余参数的列表。
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    # 遍历每个子解析器
    for name, subparser in subparsers.items():
        try:
            # 尝试用当前子解析器解析所有参数
            # parse_known_args() 返回一个包含已知参数的命名空间和未知参数列表的元组
            namespace, unknown = subparser.parse_known_args(remaining_args)
            parsed_args[name] = namespace
            remaining_args = unknown
        except:
            # 如果解析失败，继续尝试下一个子解析器
            continue

    return parsed_args, remaining_args

