def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    """
    将一个数字使用给定的字母表转换为字符串。

    数字表示一个短的 UUID。

    输出的字符串以最高有效位（Most Significant Digit）优先。

    @param number: 整型值  
    @param alphabet: 包含字母的列表  
    @param padding: 可选参数，整型值，用于指定填充长度  
    @return: 与整型值对应的字符串值
    """
    base = len(alphabet)
    result = []

    # 处理0的特殊情况
    if number == 0:
        result = [alphabet[0]]
    else:
        # 将数字转换为字符串
        while number:
            result.append(alphabet[number % base])
            number //= base

        # 反转列表以保持最高有效位优先
        result.reverse()

    # 如果指定了padding，进行填充
    if padding is not None:
        while len(result) < padding:
            result.insert(0, alphabet[0])

    return ''.join(result)

from datetime import timedelta

def parse_frequency(frequency):
    if frequency is None or frequency == "always":
        return None

    try:
        # Split frequency string into number and unit
        parts = frequency.split()
        if len(parts) != 2:
            raise ValueError(f"Invalid frequency format: {frequency}")

        number = float(parts[0])
        unit = parts[1].lower()

        # Map of valid time units to timedelta parameters
        valid_units = {
            'days': 'days',
            'day': 'days',
            'weeks': 'weeks', 
            'week': 'weeks',
            'hours': 'hours',
            'hour': 'hours',
            'minutes': 'minutes',
            'minute': 'minutes',
            'seconds': 'seconds',
            'second': 'seconds',
            'microseconds': 'microseconds',
            'microsecond': 'microseconds'
        }

        if unit not in valid_units:
            raise ValueError(f"Invalid time unit: {unit}")

        # Create timedelta with the appropriate unit
        kwargs = {valid_units[unit]: number}
        return timedelta(**kwargs)

    except ValueError as e:
        if str(e).startswith("Invalid"):
            raise
        raise ValueError(f"Invalid frequency format: {frequency}")

def make_find_paths(find_paths):
    result = []
    for path in find_paths:
        # Skip paths that already have glob patterns
        if any(c in path for c in '*?[]'):
            result.append(path)
            continue

        # Skip paths with special prefixes like pp:
        if ':' in path:
            result.append(path)
            continue

        # Convert normal paths to glob pattern
        # Add **/* prefix and */** suffix to match file anywhere in directory tree
        glob_path = f'sh:**/*{path}*/**'
        result.append(glob_path)

    return tuple(result)

def oneline(script, separator=" && "):
    # Split script into lines and remove empty lines
    lines = [line.strip() for line in script.split('\n') if line.strip()]

    # Join lines with separator
    return separator.join(lines)

def remove_ending_os_sep(input_list):
    import os

    # Handle None input
    if input_list is None:
        return []

    # Check input type
    if not isinstance(input_list, list):
        raise TypeError("Input must be a list")

    result = []

    # Process each string in list
    for path in input_list:
        # Skip if not string
        if not isinstance(path, str):
            result.append(path)
            continue

        # Skip if empty or single char
        if len(path) <= 1:
            result.append(path)
            continue

        # Remove trailing separator if exists
        if path[-1] == os.sep:
            result.append(path[:-1])
        else:
            result.append(path)

    return result

def _dump_string(obj, dumper=None):
    """
    给定一个 Python 对象并将其序列化为 YAML 流

    参数：
        obj：Python 对象

    返回值：
        YAML 流

    将对象转储为 Python 2 的 Unicode 字符串或 Python 3 的字符串。
    """
    if isinstance(obj, str):
        return obj

    # Handle Python 2 unicode strings
    try:
        if isinstance(obj, unicode):
            return obj
    except NameError:
        pass

    # Convert other types to string
    try:
        return str(obj)
    except:
        return repr(obj)

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    """
    根据一系列配置文件名，加载并验证每个配置文件。如果由于权限不足或解析配置文件出错导致无法读取配置文件，将记录错误日志。否则，将结果以一个元组的形式返回，包含一个将配置文件名映射到相应的解析后的配置的字典和一个包含所有解析错误的 `logging.LogRecord` 实例序列。
    根据一系列配置文件名，加载并验证每个配置文件。将结果以一个元组的形式返回，包含一个将配置文件名映射到相应的解析后的配置的字典和一个包含所有解析错误的 `logging.LogRecord` 实例序列。
    """
    import yaml
    import os
    import logging
    from pathlib import Path

    # Initialize return values
    configs = {}
    error_logs = []
    logger = logging.getLogger(__name__)

    # Process each config file
    for filename in config_filenames:
        try:
            path = Path(filename)

            # Check if file exists
            if not path.exists():
                raise FileNotFoundError(f"Configuration file not found: {filename}")

            # Read and parse YAML file
            with open(path, 'r') as f:
                config = yaml.safe_load(f)

            # Resolve environment variables if requested
            if resolve_env:
                config = _resolve_env_vars(config)

            # Apply overrides if provided
            if overrides:
                config = _apply_overrides(config, overrides)

            configs[filename] = config

        except (PermissionError, yaml.YAMLError) as e:
            error_record = logger.makeLogRecord({
                'msg': f"Error loading configuration file {filename}: {str(e)}",
                'levelno': logging.ERROR,
                'exc_info': True
            })
            error_logs.append(error_record)
            logger.handle(error_record)

    return configs, error_logs

def _resolve_env_vars(config):
    """Helper function to resolve environment variables in config"""
    if isinstance(config, dict):
        return {k: _resolve_env_vars(v) for k, v in config.items()}
    elif isinstance(config, list):
        return [_resolve_env_vars(v) for v in config]
    elif isinstance(config, str) and config.startswith('${') and config.endswith('}'):
        env_var = config[2:-1]
        return os.environ.get(env_var, config)
    return config

def _apply_overrides(config, overrides):
    """Helper function to apply configuration overrides"""
    if isinstance(config, dict) and isinstance(overrides, dict):
        for k, v in overrides.items():
            if k in config and isinstance(config[k], dict) and isinstance(v, dict):
                config[k] = _apply_overrides(config[k], v)
            else:
                config[k] = v
    return config

def force_string(obj):
    """
    如果对象是 `numpy.bytes` 或 `bytes` 类型，则强制使用 'utf-8' 解码。

    参数：
        obj: 一致性配置
    返回值：
        如果对象是字符串类型，则返回对应的 UTF-8 编码的字节对象；否则，直接返回该对象。

    此函数在对象是字符串的情况下，返回对应的 UTF-8 编码的字节对象。
    """
    # 检查是否为numpy.bytes类型
    if hasattr(obj, 'dtype') and obj.dtype.kind == 'S':
        return obj.decode('utf-8')

    # 检查是否为bytes类型
    if isinstance(obj, bytes):
        return obj.decode('utf-8')

    return obj

def protocol_handlers(cls, protocol_version=None):
    # 存储所有支持的协议版本和对应的处理程序
    handlers = {
        (3, 0): BoltProtocolV3,
        (4, 0): BoltProtocolV4,
        (4, 1): BoltProtocolV4_1,
        (4, 2): BoltProtocolV4_2,
        (4, 3): BoltProtocolV4_3,
        (4, 4): BoltProtocolV4_4,
        (5, 0): BoltProtocolV5
    }

    # 如果未指定版本,返回所有支持的处理程序
    if protocol_version is None:
        return handlers

    # 检查协议版本参数类型
    if not isinstance(protocol_version, tuple):
        raise TypeError("Protocol version must be specified as a tuple")

    # 如果指定了版本,只返回该版本的处理程序(如果支持)
    if protocol_version in handlers:
        return {protocol_version: handlers[protocol_version]}

    # 如果指定的版本不支持,返回空字典
    return {}

def _get_seq_with_type(seq, bufsize=None):
    """
    返回一个 (sequence, type) 对。
    sequence 是从 *seq* 派生的
    （或者是 *seq* 本身，如果它是一个序列类型）。
    """
    # 检查是否为序列类型
    if isinstance(seq, (list, tuple, bytes, bytearray)):
        return seq, type(seq)

    # 如果是迭代器或生成器,转换为列表
    if hasattr(seq, '__iter__'):
        if bufsize is not None:
            # 如果指定了bufsize,只获取指定长度
            seq_list = []
            for i, item in enumerate(seq):
                if i >= bufsize:
                    break
                seq_list.append(item)
            return seq_list, list
        else:
            # 否则获取全部
            return list(seq), list

    # 如果不是序列也不是可迭代对象,包装成列表
    return [seq], list

def _verify(iface, candidate, tentative=False, vtype=None):
    from zope.interface.exceptions import Invalid, DoesNotImplement
    from zope.interface.verify import verifyObject
    from zope.interface.interface import Method

    errors = []

    # Step 1: Check if candidate declares it provides the interface
    if not tentative:
        if not iface.providedBy(candidate):
            errors.append(DoesNotImplement(iface))

    # Step 2 & 3: Check methods and their signatures
    for name, desc in iface.namesAndDescriptions(1):
        if isinstance(desc, Method):
            # Check if method exists
            try:
                attr = getattr(candidate, name)
            except AttributeError:
                errors.append(Invalid(f"The '{name}' attribute was not provided."))
                continue

            # Verify it's callable
            if not callable(attr):
                errors.append(Invalid(f"The '{name}' attribute is not callable."))
                continue

            # Check method signature if possible
            try:
                if hasattr(desc, 'getSignatureInfo'):
                    sig_info = desc.getSignatureInfo()
                    method_sig = verifyObject(sig_info, attr)
                    if not method_sig:
                        errors.append(Invalid(f"The '{name}' method has incorrect signature."))
            except Exception as e:
                errors.append(Invalid(f"Error verifying signature of '{name}': {str(e)}"))

    # Step 4: Check attributes
    for name, desc in iface.namesAndDescriptions(1):
        if not isinstance(desc, Method):
            try:
                getattr(candidate, name)
            except AttributeError:
                errors.append(Invalid(f"The '{name}' attribute was not provided."))

    # Handle errors
    if len(errors) == 0:
        return True
    elif len(errors) == 1:
        raise errors[0]
    else:
        raise Invalid(f"Multiple errors: {'; '.join(str(e) for e in errors)}")

def verifyObject(iface, candidate, tentative=False):
    from zope.interface.exceptions import Invalid, DoesNotImplement, BrokenImplementation, BrokenMethodImplementation
    from zope.interface.verify import verifyClass
    from zope.interface.interface import Method

    # Step 1: Check if candidate provides interface
    if not tentative:
        if not iface.providedBy(candidate):
            raise DoesNotImplement(iface)

    # Collect all errors
    errors = []

    # Step 2 & 3: Check methods
    for name, desc in iface.namesAndDescriptions(1):
        if isinstance(desc, Method):
            # Check if method exists
            try:
                attr = getattr(candidate, name)
            except AttributeError:
                errors.append(BrokenImplementation(iface, name))
                continue

            # Check if it's callable
            if not callable(attr):
                errors.append(BrokenMethodImplementation(name, "Not a method"))
                continue

            # Check method signature
            try:
                verifyClass(iface, attr.__class__)
            except Invalid as e:
                errors.append(BrokenMethodImplementation(name, str(e)))

    # Step 4: Check attributes
    for name, desc in iface.namesAndDescriptions(1):
        if not isinstance(desc, Method):
            try:
                getattr(candidate, name)
            except AttributeError:
                errors.append(BrokenImplementation(iface, name))

    # Raise collected errors
    if len(errors) == 1:
        raise errors[0]
    elif errors:
        raise Invalid(errors)

    return True

def determineMetaclass(bases, explicit_mc=None):
    """
    从一个或多个基类以及可选的显式 __metaclass__ 中确定元类。
    """
    metaclasses = []

    # 收集所有基类的元类
    for base in bases:
        if hasattr(base, '__class__'):
            metaclasses.append(type(base))

    # 如果有显式指定的元类,添加到列表中
    if explicit_mc is not None:
        metaclasses.append(explicit_mc)

    if not metaclasses:
        return type

    # 如果只有一个元类,直接返回
    if len(metaclasses) == 1:
        return metaclasses[0]

    # 如果有多个元类,找出最具体的那个
    candidate = metaclasses[0]
    for mc in metaclasses[1:]:
        if issubclass(candidate, mc):
            continue
        if issubclass(mc, candidate):
            candidate = mc
        else:
            raise TypeError("Incompatible metaclasses")

    return candidate

def pop(self, key, default=__marker):
    try:
        value = self[key]
        del self[key]
        return value
    except KeyError:
        if default is not __marker:
            return default
        raise

def _create_converter(self) -> _converting._Converter:
    """
    创建参数样式转换器。

    返回参数样式转换器 (:class:`._converting._Converter`)。
    """
    return _converting._Converter()

def parse(self, timestr, default=None, ignoretz=False, tzinfos=None, **kwargs):
    """Parse date/time string to datetime.datetime object."""

    if not isinstance(timestr, str):
        raise TypeError("Parser must be given a string or character stream, not '%s'" % type(timestr).__name__)

    # Default handling
    if default is not None and not isinstance(default, datetime.datetime):
        raise TypeError("Default must be a datetime.datetime object")

    res = self._parse(timestr, **kwargs)

    if res is None:
        raise ParserError("Unknown string format: %s" % timestr)

    # Extract datetime components
    year = res.year if res.year is not None else default.year if default else None
    month = res.month if res.month is not None else default.month if default else None  
    day = res.day if res.day is not None else default.day if default else None
    hour = res.hour if res.hour is not None else default.hour if default else 0
    minute = res.minute if res.minute is not None else default.minute if default else 0
    second = res.second if res.second is not None else default.second if default else 0
    microsecond = res.microsecond if res.microsecond is not None else default.microsecond if default else 0

    if year is None or month is None or day is None:
        raise ParserError("Required date fields not found")

    # Handle timezone
    tzinfo = None
    if not ignoretz:
        if res.tzname:
            if tzinfos:
                if callable(tzinfos):
                    tzinfo = tzinfos(res.tzname, res.tzoffset)
                else:
                    if res.tzname in tzinfos:
                        tzinfo = tzinfos[res.tzname]
                if tzinfo is not None and not isinstance(tzinfo, datetime.tzinfo):
                    tzinfo = datetime.timezone(datetime.timedelta(seconds=tzinfo))
            elif res.tzoffset is not None:
                tzinfo = datetime.timezone(datetime.timedelta(seconds=res.tzoffset))

    try:
        dt = datetime.datetime(year, month, day, hour, minute, second, 
                             microsecond, tzinfo=tzinfo)
    except (ValueError, OverflowError) as e:
        raise ParserError(str(e))

    if kwargs.get('fuzzy_with_tokens', False):
        return dt, res.tokens

    return dt

def identify_request(request: RequestType):
    # Try to load as JSON first
    try:
        json_data = json.loads(request.body)
        # Check if it contains events
        if 'events' in json_data:
            return True
    except (json.JSONDecodeError, AttributeError):
        pass

    # Try XML if JSON fails
    try:
        xml_data = ET.fromstring(request.body)
        # Check if root tag is Magic_ENV_TAG
        if xml_data.tag == 'Magic_ENV_TAG':
            return True
    except (ET.ParseError, AttributeError):
        pass

    # If neither condition is met, return False
    return False

def identify_request(request: RequestType) -> bool:
    """
    检查通过 JSON 加载的请求体是否包含事件。如果包含，则返回真。否则，返回假。

    尝试识别这是否是一个 Matrix 请求。
    """
    # Check if request is a dict
    if not isinstance(request, dict):
        return False

    # Check if request contains events
    if 'events' not in request:
        return False

    # Check if events is a list
    if not isinstance(request['events'], list):
        return False

    # Check if there are any events
    if len(request['events']) == 0:
        return False

    # Check if each event is a dict
    for event in request['events']:
        if not isinstance(event, dict):
            return False

    # If all checks pass, this appears to be a valid Matrix request
    return True

def xml_children_as_dict(node):
    """
    将 <xml> 节点的子节点转换为一个字典，以标签名称作为键。

    这只是一个浅层转换——子节点不会被递归处理。
    """
    result = {}
    for child in node:
        # 跳过注释等非元素节点
        if not hasattr(child, 'tag'):
            continue
        # 使用标签名作为键,节点对象作为值
        result[child.tag] = child
    return result

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    通过读取 JSON 格式的文档获取 Webfinger，Webfinger 中的 `hcard_url` 值是文档中 `links` 的 `href` 值。

    解析 Diaspora 的 Webfinger，该 Webfinger 可以是 JSON 格式（新格式）或 XRD 格式（旧格式）。

    https://diaspora.github.io/diaspora_federation/discovery/webfinger.html
    """
    import json
    from typing import Dict
    import xml.etree.ElementTree as ET

    # Try parsing as JSON first
    try:
        data = json.loads(document)

        # Look for hcard_url in links
        for link in data.get('links', []):
            if link.get('rel') == 'http://microformats.org/profile/hcard':
                return {'hcard_url': link.get('href')}

    except json.JSONDecodeError:
        # If JSON parsing fails, try XRD format
        try:
            # Remove XML namespace to simplify parsing
            document = document.replace('xmlns="http://docs.oasis-open.org/ns/xri/xrd-1.0"', '')
            root = ET.fromstring(document)

            # Look for Link element with hcard rel
            for link in root.findall('.//Link'):
                rel = link.get('rel')
                if rel == 'http://microformats.org/profile/hcard':
                    return {'hcard_url': link.get('href')}

        except ET.ParseError:
            pass

    # Return empty dict if no hcard_url found
    return {'hcard_url': None}

def retrieve_and_parse_diaspora_webfinger(handle):
    """
    检索并解析远程 Diaspora WebFinger 文档。

    :arg handle: 要检索的远程句柄 
    :returns: 字典
    """
    import requests
    import json
    from urllib.parse import urlparse

    # 验证句柄格式
    if '@' not in handle:
        raise ValueError("Invalid handle format")

    username, domain = handle.split('@', 1)

    # 构建 WebFinger URL
    webfinger_url = f"https://{domain}/.well-known/webfinger"
    params = {
        'resource': f'acct:{handle}'
    }

    try:
        # 发送请求获取 WebFinger 文档
        response = requests.get(webfinger_url, params=params)
        response.raise_for_status()

        # 解析 JSON 响应
        data = response.json()

        # 提取相关信息到字典
        result = {
            'handle': handle,
            'username': username,
            'domain': domain,
            'links': {}
        }

        # 解析链接
        if 'links' in data:
            for link in data['links']:
                rel = link.get('rel', '')
                href = link.get('href', '')
                if rel and href:
                    result['links'][rel] = href

        # 添加其他可能的字段
        if 'subject' in data:
            result['subject'] = data['subject']
        if 'aliases' in data:
            result['aliases'] = data['aliases']

        return result

    except requests.exceptions.RequestException as e:
        raise ConnectionError(f"Failed to retrieve WebFinger document: {str(e)}")
    except json.JSONDecodeError:
        raise ValueError("Invalid WebFinger document format")

def list_of_file_names(settings_dirs, spec_option):
    """
    通过 `cli.ListOfFileNames()` 创建并返回一个新的 `IniType` 复合类型。
    创建一个新的 `IniType` 复合类型。
    """
    class ListOfFileNames:
        def __init__(self):
            self.settings_dirs = settings_dirs
            self.spec_option = spec_option
            self.files = []

        def get_files(self):
            """获取文件列表"""
            import os
            for directory in self.settings_dirs:
                if os.path.exists(directory):
                    for file in os.listdir(directory):
                        if file.endswith(self.spec_option):
                            full_path = os.path.join(directory, file)
                            self.files.append(full_path)
            return self.files

    file_names = ListOfFileNames()
    return file_names.get_files()

