def validate_from_content(cls, spec_content=None):
    """
    验证规范（YAML）内容是否包含所有必需字段。

    :param spec_content: 规范文件的内容
    :raise IRValidatorException: 当规范文件中缺少必需数据时抛出异常 
    :return: 从规范（YAML）文件加载的数据字典
    """
    if spec_content is None:
        raise IRValidatorException("规范内容不能为空")

    try:
        # 尝试加载YAML内容
        import yaml
        data = yaml.safe_load(spec_content)

        # 验证是否为字典
        if not isinstance(data, dict):
            raise IRValidatorException("规范内容必须是有效的YAML字典格式")

        # 检查必需字段
        required_fields = ['name', 'version', 'description']
        missing_fields = []

        for field in required_fields:
            if field not in data:
                missing_fields.append(field)

        if missing_fields:
            raise IRValidatorException(
                f"规范中缺少以下必需字段: {', '.join(missing_fields)}"
            )

        return data

    except yaml.YAMLError as e:
        raise IRValidatorException(f"无效的YAML格式: {str(e)}")
    except Exception as e:
        raise IRValidatorException(f"验证规范内容时发生错误: {str(e)}")

def validate_from_file(cls, yaml_file=None):
    """
    加载并验证一个 YAML 文件是否包含所有必需字段

    :param yaml_file: YAML 文件的路径 
    :raise IRValidatorException: 当文件中缺少必需数据时抛出异常
    :return: 从 YAML 文件加载的数据字典
    """
    try:
        import yaml

        if yaml_file is None:
            raise IRValidatorException("YAML file path cannot be None")

        # 读取YAML文件
        with open(yaml_file, 'r', encoding='utf-8') as f:
            data = yaml.safe_load(f)

        if not isinstance(data, dict):
            raise IRValidatorException("YAML file must contain a dictionary")

        # 验证必需字段
        required_fields = cls.get_required_fields()
        missing_fields = []

        for field in required_fields:
            if field not in data:
                missing_fields.append(field)

        if missing_fields:
            raise IRValidatorException(
                f"Missing required fields in YAML file: {', '.join(missing_fields)}"
            )

        return data

    except yaml.YAMLError as e:
        raise IRValidatorException(f"Error parsing YAML file: {str(e)}")
    except FileNotFoundError:
        raise IRValidatorException(f"YAML file not found: {yaml_file}")
    except Exception as e:
        raise IRValidatorException(f"Unexpected error: {str(e)}")

def _include_groups(self, parser_dict):
    """
    解析规范文件中的 include dict 指令。
    """
    if not isinstance(parser_dict, dict):
        return parser_dict

    if 'include' not in parser_dict:
        return parser_dict

    included_groups = parser_dict.pop('include')

    if not isinstance(included_groups, (list, tuple)):
        included_groups = [included_groups]

    result = {}
    for group in included_groups:
        if isinstance(group, dict):
            result.update(group)
        elif isinstance(group, str):
            # 假设从某处加载group定义
            group_dict = self._load_group(group)
            result.update(group_dict)

    result.update(parser_dict)
    return result

def get_deprecated_args(self):
    """
    返回一个包含会弃用其他选项的字典。选项来自 `self.spec_helper.iterate_option_specs()`。
    返回一个包含会弃用其他选项的字典。
    """
    deprecated_args = {}

    # 遍历所有选项规格
    for spec in self.spec_helper.iterate_option_specs():
        # 检查选项是否有弃用其他选项的设置
        if hasattr(spec, 'deprecated_options') and spec.deprecated_options:
            # 将弃用选项添加到字典中
            for deprecated_opt in spec.deprecated_options:
                deprecated_args[deprecated_opt] = spec.name

    return deprecated_args

def validate_requires_args(self, args):
    """
    检查是否提供了所有必需的参数。
    """
    if not args:
        raise ValueError("No arguments provided")

    required_args = getattr(self, 'required_args', [])

    for arg in required_args:
        if arg not in args:
            raise ValueError(f"Missing required argument: {arg}")

    return True

def _get_conditionally_required_args(self, command_name, options_spec, args):
    """
    列出符合 ``required_when`` 条件的参数。

    :param command_name: 命令名称。
    :param options_spec: 命令选项规范的列表。
    :param args: 接收到的输入参数。
    :return: list，符合 ``required_when`` 条件的参数名称列表。
    """
    required_args = []

    for option in options_spec:
        # Skip if option has no required_when condition
        if 'required_when' not in option:
            continue

        required_when = option['required_when']

        # If required_when is a string (argument name)
        if isinstance(required_when, str):
            if args.get(required_when):
                required_args.append(option['name'])

        # If required_when is a dict with conditions
        elif isinstance(required_when, dict):
            conditions_met = True
            for key, value in required_when.items():
                if args.get(key) != value:
                    conditions_met = False
                    break

            if conditions_met:
                required_args.append(option['name'])

        # If required_when is a callable
        elif callable(required_when):
            if required_when(args):
                required_args.append(option['name'])

    return required_args

def validate_choices_args(self, args):
    """
    检查给定参数的值是否是可用选项之一。

    :param args: 接收到的参数。

    检查选择参数的值是否是可用选项之一。
    :param args: 接收到的参数。
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, 'choices') and arg_name in self.choices:
            valid_choices = self.choices[arg_name]
            if arg_value not in valid_choices:
                raise ValueError(f"Invalid value '{arg_value}' for argument '{arg_name}'. "
                               f"Valid choices are: {valid_choices}")

def validate_min_max_args(self, args):
    """
    检查给定参数的值是否在最小值和最大值之间

    检查参数的值是否在最小值和最大值之间
    :param args: 接收到的参数。
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'min_{arg_name}') and hasattr(self, f'max_{arg_name}'):
            min_val = getattr(self, f'min_{arg_name}')
            max_val = getattr(self, f'max_{arg_name}')

            if not isinstance(arg_value, (int, float)):
                try:
                    arg_value = float(arg_value)
                except (ValueError, TypeError):
                    raise ValueError(f"Parameter {arg_name} must be a number")

            if arg_value < min_val:
                raise ValueError(f"Parameter {arg_name} cannot be less than {min_val}")
            if arg_value > max_val:
                raise ValueError(f"Parameter {arg_name} cannot be greater than {max_val}")

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    使用 ``extra-vars`` 扩展 ``vars_dict``。

    :param vars_dict: 要合并 extra-vars 的字典
    :param extra_vars: extra-vars的列表
    """
    if not extra_vars:
        return vars_dict

    if isinstance(extra_vars, str):
        extra_vars = [extra_vars]

    for extra_var in extra_vars:
        if '=' not in extra_var:
            continue

        key, value = extra_var.split('=', 1)
        key = key.strip()
        value = value.strip()

        # Try to convert string value to appropriate type
        try:
            # Try to evaluate as literal Python expression
            parsed_value = eval(value)
            if isinstance(parsed_value, (int, float, bool, list, dict)):
                value = parsed_value
        except:
            pass

        vars_dict[key] = value

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    通过修改 values_dict 参数将参数转换为正确的类型。

    默认情况下，所有的值都是字符串。

    :param parser_name: 命令名称，例如 main、virsh、ospd 等
    :param values_dict: 包含参数的字典
    """
    if not values_dict:
        return

    # 获取该解析器的参数定义
    parser = self._parsers.get(parser_name)
    if not parser:
        return

    # 遍历所有参数
    for arg_name, value in values_dict.items():
        # 跳过None值
        if value is None:
            continue

        # 获取参数的类型
        arg_type = None
        for action in parser._actions:
            if action.dest == arg_name:
                arg_type = action.type
                break

        # 如果找到类型定义则进行转换
        if arg_type:
            try:
                # 处理列表类型
                if isinstance(value, list):
                    values_dict[arg_name] = [arg_type(v) for v in value]
                else:
                    values_dict[arg_name] = arg_type(value)
            except (ValueError, TypeError):
                # 转换失败时保持原值
                continue

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    使用 YAML 来读取 `plugin_dir` 中的各种信息，并以字典形式将其返回。
    从插件规范创建一个扁平化的字典

    :param plugin_dir: 插件目录的路径 
    :return: 一个包含插件属性的扁平化字典
    """
    import os
    import yaml

    # 初始化结果字典
    result = {}

    # 读取插件目录下的 plugin.yaml 文件
    spec_file = os.path.join(plugin_dir, 'plugin.yaml')
    if not os.path.exists(spec_file):
        return result

    # 读取 YAML 文件
    with open(spec_file, 'r', encoding='utf-8') as f:
        try:
            spec = yaml.safe_load(f)
        except yaml.YAMLError:
            return result

    def flatten_dict(d, parent_key='', sep='.'):
        """递归地将嵌套字典扁平化"""
        items = []
        for k, v in d.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k

            if isinstance(v, dict):
                items.extend(flatten_dict(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))

        return dict(items)

    # 扁平化字典
    if isinstance(spec, dict):
        result = flatten_dict(spec)

    return result
